const express = require('express');
const cors = require('cors');

const app = express();
const port = 3000;

app.use(cors({
  origin: '*',
  methods: 'GET,HEAD,PUT,PATCH,POST,DELETE',
  credentials: true,
}));

app.get('/', (req, res) => {
  res.send('API Gateway');
});

app.listen(port, () => {
  console.log(`API gateway listening at http://localhost:${port}`);
});